{
  "name": "InsightMiner AI",
  "description": "A sophisticated financial intelligence tool that extracts strategic insights from corporate earnings reports and financial filings using the Gemini API."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface FinancialData {
  revenue: string;
  ebitda: string;
  pat: string;
}

export interface StrategicPoint {
  title: string;
  value?: string;
  details: string;
  impact?: string;
}

export interface ExtractedData {
  summary: string;
  financials: FinancialData;
  investments: StrategicPoint[];
  partnerships: StrategicPoint[];
  m_a: StrategicPoint[];
  strategy: StrategicPoint[];
  future: StrategicPoint[];
}

export interface ChatMessage {
  role: 'user' | 'bot';
  text: string;
}

export enum Category {
  INVESTMENTS = 'investments',
  PARTNERSHIPS = 'partnerships',
  M_A = 'm_a',
  STRATEGY = 'strategy',
  FUTURE = 'future'
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ExtractedData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeDocuments = async (base64Pdfs: string[]): Promise<ExtractedData> => {
  const model = 'gemini-3-flash-preview';

  const fileParts = base64Pdfs.map(base64 => ({
    inlineData: { mimeType: "application/pdf", data: base64 }
  }));

  const systemPrompt = `
    You are an expert financial analyst. Analyze the provided financial documents and extract key strategic data.
    If multiple documents are provided, aggregate the insights but distinguish sources if there are conflicting or distinct strategic directions.

    Focus on:
    1. Investments & Capital Expenditure (Capex)
    2. Partnerships & Joint Ventures
    3. Strategic Developments
    4. Expansions & Acquisitions
    5. Future Plans
    6. Key Financial Performance (Revenue, EBITDA, PAT) with specific reasons for growth/decline.

    Ensure all information is fact-based.
  `;

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      summary: { type: Type.STRING, description: "A brief executive overview of all documents." },
      financials: {
        type: Type.OBJECT,
        properties: {
          revenue: { type: Type.STRING },
          ebitda: { type: Type.STRING },
          pat: { type: Type.STRING }
        },
        required: ["revenue", "ebitda", "pat"]
      },
      investments: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            value: { type: Type.STRING },
            details: { type: Type.STRING },
            impact: { type: Type.STRING }
          },
          required: ["title", "details"]
        }
      },
      partnerships: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            details: { type: Type.STRING }
          },
          required: ["title", "details"]
        }
      },
      m_a: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            details: { type: Type.STRING }
          },
          required: ["title", "details"]
        }
      },
      strategy: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            details: { type: Type.STRING }
          },
          required: ["title", "details"]
        }
      },
      future: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            details: { type: Type.STRING }
          },
          required: ["title", "details"]
        }
      }
    },
    required: ["summary", "financials", "investments", "partnerships", "m_a", "strategy", "future"]
  };

  const result = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { text: "Extract strategic financial insights from these documents." },
        ...fileParts
      ]
    },
    config: {
      systemInstruction: systemPrompt,
      responseMimeType: "application/json",
      responseSchema
    }
  });

  const text = result.text;
  if (!text) throw new Error("No response from Gemini API");
  return JSON.parse(text) as ExtractedData;
};

export const chatWithDocuments = async (base64Pdfs: string[], history: { role: string, text: string }[], message: string): Promise<string> => {
  const model = 'gemini-3-flash-preview';

  const fileParts = base64Pdfs.map(base64 => ({
    inlineData: { mimeType: "application/pdf", data: base64 }
  }));

  const systemInstruction = `You are a helpful assistant analyzing specific financial documents uploaded by the user. Answer the user's question based ONLY on the document content. Keep answers concise and relevant. If the information isn't in the documents, state that clearly.`;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        ...fileParts,
        ...history.map(h => ({ text: `${h.role === 'user' ? 'User' : 'Assistant'}: ${h.text}` })),
        { text: `Current Question: ${message}` }
      ]
    },
    config: {
      systemInstruction
    }
  });

  return response.text || "I couldn't find a relevant answer in the provided documents.";
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  Upload, Sun, Moon, AlertCircle, Loader2, LayoutDashboard,
  TrendingUp, Globe, Briefcase, Zap, PieChart, Pickaxe
} from 'lucide-react';
import { analyzeDocuments } from './services/geminiService';
import { ExtractedData, ChatMessage } from './types';
import Dashboard from './components/Dashboard';
import ChatInterface from './components/ChatInterface';

const App: React.FC = () => {
  const [pdfFiles, setPdfFiles] = useState<File[]>([]);
  const [pdfBase64List, setPdfBase64List] = useState<string[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [extractedData, setExtractedData] = useState<ExtractedData | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(true);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve((reader.result as string).split(',')[1]);
      reader.onerror = (error) => reject(error);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    if (files.length > 5) {
      setError("Maximum 5 files allowed at once.");
      return;
    }

    const validFiles = files.filter(file => file.type === 'application/pdf');
    if (validFiles.length === 0) {
      setError("Please upload valid PDF documents.");
      return;
    }

    setError(null);
    setPdfFiles(validFiles);
    setIsProcessing(true);
    setExtractedData(null);

    try {
      const base64List = await Promise.all(validFiles.map(fileToBase64));
      setPdfBase64List(base64List);
      const result = await analyzeDocuments(base64List);
      setExtractedData(result);
    } catch (err: any) {
      setError(err.message || "Failed to process documents.");
      console.error(err);
    } finally {
      setIsProcessing(false);
    }
  };

  const themeClasses = {
    bg: isDarkMode 
      ? "bg-slate-950 text-slate-200" 
      : "bg-slate-50 text-slate-900",
    header: isDarkMode
      ? "bg-slate-900/50 border-slate-800"
      : "bg-white/80 border-slate-200 shadow-sm",
    accent: "bg-gradient-to-r from-violet-600 to-indigo-600 hover:from-violet-500 hover:to-indigo-500 text-white shadow-xl shadow-indigo-500/10",
    textHeading: isDarkMode
      ? "bg-clip-text text-transparent bg-gradient-to-r from-indigo-200 via-purple-200 to-pink-200"
      : "bg-clip-text text-transparent bg-gradient-to-r from-indigo-700 via-purple-700 to-pink-700",
    card: isDarkMode
      ? "bg-slate-900/40 border-slate-800"
      : "bg-white border-slate-200 shadow-sm"
  };

  return (
    <div className={`min-h-screen transition-all duration-300 flex flex-col ${themeClasses.bg}`}>
      {/* Navigation */}
      <nav className={`sticky top-0 z-50 backdrop-blur-md border-b px-4 py-3 ${themeClasses.header}`}>
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className={`p-2 rounded-xl ${themeClasses.accent}`}>
              <LayoutDashboard className="w-5 h-5" />
            </div>
            <h1 className={`text-xl font-extrabold tracking-tight ${themeClasses.textHeading}`}>
              InsightMiner <span className="text-sm font-medium ml-1 opacity-70">AI</span>
            </h1>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => setIsDarkMode(!isDarkMode)}
              className={`p-2.5 rounded-xl transition-all border ${isDarkMode ? 'border-slate-800 bg-slate-900 text-yellow-400' : 'border-slate-200 bg-white text-indigo-600'}`}
            >
              {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>

            <button 
              onClick={() => fileInputRef.current?.click()}
              className={`${themeClasses.accent} px-5 py-2.5 rounded-xl text-sm font-semibold flex items-center gap-2 transition-transform active:scale-95`}
            >
              <Upload className="w-4 h-4" />
              {extractedData ? 'New Analysis' : 'Upload Reports'}
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileUpload} 
              className="hidden" 
              accept=".pdf" 
              multiple 
            />
          </div>
        </div>
      </nav>

      <main className="flex-grow max-w-7xl w-full mx-auto p-4 md:p-6 space-y-8">
        {error && (
          <div className="bg-red-500/10 border border-red-500/30 text-red-400 p-4 rounded-2xl flex items-center gap-3 animate-in fade-in slide-in-from-top-4">
            <AlertCircle className="w-5 h-5 flex-shrink-0" />
            <p className="font-medium">{error}</p>
          </div>
        )}

        {/* Empty State */}
        {!extractedData && !isProcessing && (
          <div className={`mt-20 flex flex-col items-center justify-center text-center p-12 rounded-[2.5rem] border-2 border-dashed transition-all duration-700 ${isDarkMode ? 'border-slate-800' : 'border-slate-200'}`}>
            <div className={`p-8 rounded-full mb-8 ${isDarkMode ? 'bg-indigo-500/10' : 'bg-indigo-50'} animate-bounce`}>
              <Pickaxe className={`w-16 h-16 ${isDarkMode ? 'text-indigo-400' : 'text-indigo-600'}`} />
            </div>
            <h2 className={`text-4xl md:text-6xl font-black mb-6 ${themeClasses.textHeading}`}>
              Mine Intelligence from Reports
            </h2>
            <p className="text-lg max-w-2xl mb-10 text-slate-400 leading-relaxed font-medium">
              Upload earnings transcripts, quarterly reports, or annual filings. Our specialized AI model extracts CAPEX trajectories, M&A signals, and strategic pivots automatically.
            </p>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className={`${themeClasses.accent} px-10 py-4 rounded-2xl text-lg font-bold shadow-2xl transition-all hover:scale-105`}
            >
              Drop Reports Here
            </button>
          </div>
        )}

        {/* Loading State */}
        {isProcessing && (
          <div className="mt-40 flex flex-col items-center justify-center space-y-6">
            <div className="relative">
              <div className="absolute inset-0 bg-indigo-500 blur-3xl opacity-20 animate-pulse"></div>
              <Loader2 className="w-20 h-20 text-indigo-500 animate-spin relative z-10" />
            </div>
            <div className="text-center">
              <h2 className="text-3xl font-bold tracking-tight mb-2">Analyzing Data</h2>
              <p className="text-slate-500 font-medium">Parsing {pdfFiles.length} document{pdfFiles.length > 1 ? 's' : ''} for strategic insights...</p>
            </div>
          </div>
        )}

        {/* Dashboard Results */}
        {extractedData && (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-10 duration-1000">
            <Dashboard data={extractedData} isDarkMode={isDarkMode} />
            <ChatInterface 
              pdfBase64List={pdfBase64List} 
              isDarkMode={isDarkMode} 
              pdfFiles={pdfFiles}
            />
          </div>
        )}
      </main>

      <footer className="py-8 text-center text-xs font-medium text-slate-500 border-t border-slate-800 mt-12">
        Powered by Gemini 3 Flash &copy; {new Date().getFullYear()} InsightMiner AI
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { 
  CheckCircle2, CircleDollarSign, BarChart3, PieChart, 
  TrendingUp, Globe, Briefcase, Zap, Sparkles 
} from 'lucide-react';
import { ExtractedData, StrategicPoint } from '../types';

interface DashboardProps {
  data: ExtractedData;
  isDarkMode: boolean;
}

const Dashboard: React.FC<DashboardProps> = ({ data, isDarkMode }) => {
  const categories = [
    { id: 'investments', label: 'Investments & Capex', icon: <TrendingUp className="w-5 h-5" />, color: 'blue' },
    { id: 'partnerships', label: 'Partnerships & JVs', icon: <Globe className="w-5 h-5" />, color: 'emerald' },
    { id: 'm_a', label: 'M&A & Expansions', icon: <Briefcase className="w-5 h-5" />, color: 'amber' },
    { id: 'strategy', label: 'Strategic Dev', icon: <Zap className="w-5 h-5" />, color: 'purple' },
    { id: 'future', label: 'Future Plans', icon: <PieChart className="w-5 h-5" />, color: 'rose' },
  ];

  const cardBase = `p-6 rounded-3xl border transition-all duration-300 ${
    isDarkMode ? 'bg-slate-900/40 border-slate-800' : 'bg-white border-slate-200'
  }`;

  return (
    <div className="space-y-8">
      {/* Executive Summary */}
      <section className={`${cardBase} relative overflow-hidden group`}>
        <div className={`absolute top-0 right-0 p-32 opacity-10 blur-[100px] rounded-full pointer-events-none transition-opacity duration-500 group-hover:opacity-20 ${
          isDarkMode ? 'bg-indigo-500' : 'bg-indigo-300'
        }`}></div>
        <div className="flex items-center gap-3 mb-6 relative z-10">
          <div className="p-2 bg-emerald-500/20 text-emerald-500 rounded-lg">
            <CheckCircle2 className="w-6 h-6" />
          </div>
          <h3 className="text-2xl font-bold tracking-tight">Executive Intelligence</h3>
        </div>
        <p className={`text-lg leading-relaxed relative z-10 font-medium ${
          isDarkMode ? 'text-slate-300' : 'text-slate-700'
        }`}>
          {data.summary}
        </p>
      </section>

      {/* Financial Quick View */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { label: 'Revenue', value: data.financials.revenue, icon: <CircleDollarSign />, color: 'blue' },
          { label: 'EBITDA', value: data.financials.ebitda, icon: <BarChart3 />, color: 'purple' },
          { label: 'PAT', value: data.financials.pat, icon: <PieChart />, color: 'emerald' },
        ].map((fin, idx) => (
          <div key={idx} className={`${cardBase} flex flex-col justify-between hover:scale-[1.02]`}>
            <div className="flex items-center gap-3 mb-4">
              <div className={`p-2 rounded-xl bg-${fin.color}-500/10 text-${fin.color}-500`}>
                {fin.icon}
              </div>
              <h4 className="font-bold text-lg">{fin.label}</h4>
            </div>
            <p className={`text-sm leading-relaxed font-medium opacity-80`}>
              {fin.value || "Data unavailable."}
            </p>
          </div>
        ))}
      </div>

      {/* Categorized Insights Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {categories.map((cat) => {
          const points = (data[cat.id as keyof ExtractedData] as StrategicPoint[]) || [];
          if (points.length === 0) return null;

          return (
            <div key={cat.id} className={`${cardBase} h-full flex flex-col hover:shadow-2xl hover:shadow-indigo-500/5`}>
              <div className="flex items-center justify-between mb-8 pb-4 border-b border-slate-800/50">
                <div className="flex items-center gap-3">
                  <div className={`p-2.5 rounded-xl bg-indigo-500/10 text-indigo-400`}>
                    {cat.icon}
                  </div>
                  <h3 className="text-lg font-bold">{cat.label}</h3>
                </div>
                <span className="text-xs px-2.5 py-1 rounded-full bg-slate-800 text-slate-400 font-bold border border-slate-700">
                  {points.length}
                </span>
              </div>

              <div className="space-y-5 flex-grow">
                {points.map((item, idx) => (
                  <div key={idx} className={`p-5 rounded-2xl border transition-all ${
                    isDarkMode ? 'bg-black/20 border-slate-800 hover:border-indigo-500/30' : 'bg-slate-50 border-slate-200 hover:border-indigo-300'
                  }`}>
                    <div className="flex justify-between items-start mb-3 gap-4">
                      <h4 className={`font-bold text-sm leading-tight ${
                        isDarkMode ? 'text-indigo-200' : 'text-indigo-900'
                      }`}>
                        {item.title}
                      </h4>
                      {item.value && (
                        <span className="shrink-0 text-[10px] font-black px-2 py-0.5 rounded-md bg-emerald-500/10 text-emerald-400 border border-emerald-500/20">
                          {item.value}
                        </span>
                      )}
                    </div>
                    <p className="text-xs leading-relaxed text-slate-400 font-medium">{item.details}</p>
                    {item.impact && (
                      <div className="mt-4 pt-3 border-t border-dashed border-slate-800/50 flex items-center gap-2">
                        <Sparkles className="w-3 h-3 text-amber-400" />
                        <span className="text-[10px] font-bold text-amber-200/70 tracking-wide uppercase">Impact: {item.impact}</span>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, MessageSquare, Loader2, Files, Sparkles } from 'lucide-react';
import { ChatMessage } from '../types';
import { chatWithDocuments } from '../services/geminiService';

interface ChatInterfaceProps {
  pdfBase64List: string[];
  isDarkMode: boolean;
  pdfFiles: File[];
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ pdfBase64List, isDarkMode, pdfFiles }) => {
  const [chatInput, setChatInput] = useState('');
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [chatHistory, isLoading]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', text: chatInput };
    setChatHistory(prev => [...prev, userMsg]);
    setChatInput('');
    setIsLoading(true);

    try {
      const response = await chatWithDocuments(pdfBase64List, chatHistory, chatInput);
      setChatHistory(prev => [...prev, { role: 'bot', text: response }]);
    } catch (err) {
      setChatHistory(prev => [...prev, { role: 'bot', text: "I encountered an error while analyzing your request." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const cardClass = isDarkMode ? 'bg-slate-900/40 border-slate-800' : 'bg-white border-slate-200 shadow-sm';

  return (
    <section className={`rounded-[2rem] overflow-hidden border ${cardClass} flex flex-col lg:flex-row min-h-[600px]`}>
      {/* Sidebar Info */}
      <div className={`p-8 lg:w-1/3 flex flex-col justify-between border-b lg:border-b-0 lg:border-r ${
        isDarkMode ? 'bg-black/20 border-slate-800' : 'bg-indigo-50/30 border-slate-200'
      }`}>
        <div className="space-y-8">
          <div>
            <div className="flex items-center gap-3 mb-4">
              <div className="p-2 rounded-xl bg-violet-500/20 text-violet-400">
                <MessageSquare className="w-5 h-5" />
              </div>
              <h3 className="text-xl font-bold tracking-tight">Deep Dive Analyst</h3>
            </div>
            <p className="text-sm text-slate-400 leading-relaxed font-medium">
              Ask specific questions about the {pdfFiles.length} documents uploaded. I can compare figures across reports, explain strategic pivots, or verify specific financial claims.
            </p>
          </div>

          <div className="space-y-4">
            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">Context Source</h4>
            <div className="space-y-2">
              {pdfFiles.map((file, i) => (
                <div key={i} className="flex items-center gap-3 p-3 rounded-xl bg-slate-800/20 border border-slate-800/40">
                  <Files className="w-3.5 h-3.5 text-indigo-400" />
                  <span className="text-xs font-bold truncate opacity-80">{file.name}</span>
                </div>
              ))}
            </div>
          </div>

          <div className="space-y-3">
             <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">Sample Queries</h4>
             {["Detail the ESG roadmap.", "Compare Q4 vs Q3 margins.", "What are the major risk factors?"].map((q, i) => (
               <button 
                key={i}
                onClick={() => setChatInput(q)}
                className={`w-full text-left text-xs p-4 rounded-xl transition-all border ${
                  isDarkMode ? 'bg-slate-900 border-slate-800 hover:border-indigo-500/50' : 'bg-white border-slate-200 hover:border-indigo-300'
                } font-semibold`}
               >
                 {q}
               </button>
             ))}
          </div>
        </div>
      </div>

      {/* Chat Area */}
      <div className="flex-1 flex flex-col p-6 relative">
        <div className="flex-1 overflow-y-auto space-y-6 mb-6 pr-2 custom-scrollbar">
          {chatHistory.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center opacity-30 text-center">
              <div className="w-24 h-24 rounded-full bg-indigo-500/10 flex items-center justify-center mb-6 animate-pulse">
                <Bot className="w-12 h-12 text-indigo-400" />
              </div>
              <p className="text-lg font-bold">Waiting for your query...</p>
              <p className="text-sm">Type a question below to start exploring the documents.</p>
            </div>
          )}

          {chatHistory.map((msg, i) => (
            <div key={i} className={`flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''} animate-in fade-in slide-in-from-bottom-2`}>
              <div className={`w-10 h-10 rounded-2xl flex items-center justify-center flex-shrink-0 shadow-lg ${
                msg.role === 'user' ? 'bg-emerald-600' : 'bg-indigo-600'
              }`}>
                {msg.role === 'user' ? <User className="w-5 h-5 text-white" /> : <Bot className="w-5 h-5 text-white" />}
              </div>
              <div className={`p-5 rounded-[1.5rem] max-w-[85%] text-sm leading-relaxed shadow-sm font-medium ${
                msg.role === 'user'
                  ? `${isDarkMode ? 'bg-emerald-500/10 text-emerald-100 border border-emerald-500/20' : 'bg-emerald-50 text-emerald-900 border border-emerald-100'} rounded-tr-none`
                  : `${isDarkMode ? 'bg-slate-800/80 text-slate-200 border border-slate-700' : 'bg-slate-50 text-slate-800 border border-slate-200'} rounded-tl-none`
              }`}>
                {msg.text}
              </div>
            </div>
          ))}

          {isLoading && (
            <div className="flex gap-4">
