import React, { useState, useRef, useEffect } from 'react';
import { 
  Upload, Sun, Moon, AlertCircle, Loader2, LayoutDashboard,
  TrendingUp, Globe, Briefcase, Zap, PieChart, Pickaxe
} from 'lucide-react';
import { analyzeDocuments } from './services/geminiService';
import { ExtractedData, ChatMessage } from './types';
import Dashboard from './components/Dashboard';
import ChatInterface from './components/ChatInterface';

const App: React.FC = () => {
  const [pdfFiles, setPdfFiles] = useState<File[]>([]);
  const [pdfBase64List, setPdfBase64List] = useState<string[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [extractedData, setExtractedData] = useState<ExtractedData | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(true);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve((reader.result as string).split(',')[1]);
      reader.onerror = (error) => reject(error);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    // Cast to File[] to ensure the type is known for subsequent property access like file.type
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    if (files.length > 5) {
      setError("Maximum 5 files allowed at once.");
      return;
    }

    const validFiles = files.filter(file => file.type === 'application/pdf');
    if (validFiles.length === 0) {
      setError("Please upload valid PDF documents.");
      return;
    }

    setError(null);
    setPdfFiles(validFiles);
    setIsProcessing(true);
    setExtractedData(null);

    try {
      const base64List = await Promise.all(validFiles.map(fileToBase64));
      setPdfBase64List(base64List);
      const result = await analyzeDocuments(base64List);
      setExtractedData(result);
    } catch (err: any) {
      setError(err.message || "Failed to process documents.");
      console.error(err);
    } finally {
      setIsProcessing(false);
    }
  };

  const themeClasses = {
    bg: isDarkMode 
      ? "bg-slate-950 text-slate-200" 
      : "bg-slate-50 text-slate-900",
    header: isDarkMode
      ? "bg-slate-900/50 border-slate-800"
      : "bg-white/80 border-slate-200 shadow-sm",
    accent: "bg-gradient-to-r from-violet-600 to-indigo-600 hover:from-violet-500 hover:to-indigo-500 text-white shadow-xl shadow-indigo-500/10",
    textHeading: isDarkMode
      ? "bg-clip-text text-transparent bg-gradient-to-r from-indigo-200 via-purple-200 to-pink-200"
      : "bg-clip-text text-transparent bg-gradient-to-r from-indigo-700 via-purple-700 to-pink-700",
    card: isDarkMode
      ? "bg-slate-900/40 border-slate-800"
      : "bg-white border-slate-200 shadow-sm"
  };

  return (
    <div className={`min-h-screen transition-all duration-300 flex flex-col ${themeClasses.bg}`}>
      {/* Navigation */}
      <nav className={`sticky top-0 z-50 backdrop-blur-md border-b px-4 py-3 ${themeClasses.header}`}>
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className={`p-2 rounded-xl ${themeClasses.accent}`}>
              <LayoutDashboard className="w-5 h-5" />
            </div>
            <h1 className={`text-xl font-extrabold tracking-tight ${themeClasses.textHeading}`}>
              InsightMiner <span className="text-sm font-medium ml-1 opacity-70">AI</span>
            </h1>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => setIsDarkMode(!isDarkMode)}
              className={`p-2.5 rounded-xl transition-all border ${isDarkMode ? 'border-slate-800 bg-slate-900 text-yellow-400' : 'border-slate-200 bg-white text-indigo-600'}`}
            >
              {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>

            <button 
              onClick={() => fileInputRef.current?.click()}
              className={`${themeClasses.accent} px-5 py-2.5 rounded-xl text-sm font-semibold flex items-center gap-2 transition-transform active:scale-95`}
            >
              <Upload className="w-4 h-4" />
              {extractedData ? 'New Analysis' : 'Upload Reports'}
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileUpload} 
              className="hidden" 
              accept=".pdf" 
              multiple 
            />
          </div>
        </div>
      </nav>

      <main className="flex-grow max-w-7xl w-full mx-auto p-4 md:p-6 space-y-8">
        {error && (
          <div className="bg-red-500/10 border border-red-500/30 text-red-400 p-4 rounded-2xl flex items-center gap-3 animate-in fade-in slide-in-from-top-4">
            <AlertCircle className="w-5 h-5 flex-shrink-0" />
            <p className="font-medium">{error}</p>
          </div>
        )}

        {/* Empty State */}
        {!extractedData && !isProcessing && (
          <div className={`mt-20 flex flex-col items-center justify-center text-center p-12 rounded-[2.5rem] border-2 border-dashed transition-all duration-700 ${isDarkMode ? 'border-slate-800' : 'border-slate-200'}`}>
            <div className={`p-8 rounded-full mb-8 ${isDarkMode ? 'bg-indigo-500/10' : 'bg-indigo-50'} animate-bounce`}>
              <Pickaxe className={`w-16 h-16 ${isDarkMode ? 'text-indigo-400' : 'text-indigo-600'}`} />
            </div>
            <h2 className={`text-4xl md:text-6xl font-black mb-6 ${themeClasses.textHeading}`}>
              Mine Intelligence from Reports
            </h2>
            <p className="text-lg max-w-2xl mb-10 text-slate-400 leading-relaxed font-medium">
              Upload earnings transcripts, quarterly reports, or annual filings. Our specialized AI model extracts CAPEX trajectories, M&A signals, and strategic pivots automatically.
            </p>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className={`${themeClasses.accent} px-10 py-4 rounded-2xl text-lg font-bold shadow-2xl transition-all hover:scale-105`}
            >
              Drop Reports Here
            </button>
          </div>
        )}

        {/* Loading State */}
        {isProcessing && (
          <div className="mt-40 flex flex-col items-center justify-center space-y-6">
            <div className="relative">
              <div className="absolute inset-0 bg-indigo-500 blur-3xl opacity-20 animate-pulse"></div>
              <Loader2 className="w-20 h-20 text-indigo-500 animate-spin relative z-10" />
            </div>
            <div className="text-center">
              <h2 className="text-3xl font-bold tracking-tight mb-2">Analyzing Data</h2>
              <p className="text-slate-500 font-medium">Parsing {pdfFiles.length} document{pdfFiles.length > 1 ? 's' : ''} for strategic insights...</p>
            </div>
          </div>
        )}

        {/* Dashboard Results */}
        {extractedData && (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-10 duration-1000">
            <Dashboard data={extractedData} isDarkMode={isDarkMode} />
            <ChatInterface 
              pdfBase64List={pdfBase64List} 
              isDarkMode={isDarkMode} 
              pdfFiles={pdfFiles}
            />
          </div>
        )}
      </main>

      <footer className="py-8 text-center text-xs font-medium text-slate-500 border-t border-slate-800 mt-12">
        Powered by Gemini 3 Flash &copy; {new Date().getFullYear()} InsightMiner AI
      </footer>
    </div>
  );
};

