import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, MessageSquare, Loader2, Files, Sparkles } from 'lucide-react';
import { ChatMessage } from '../types';
import { chatWithDocuments } from '../services/geminiService';

interface ChatInterfaceProps {
  pdfBase64List: string[];
  isDarkMode: boolean;
  pdfFiles: File[];
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ pdfBase64List, isDarkMode, pdfFiles }) => {
  const [chatInput, setChatInput] = useState('');
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [chatHistory, isLoading]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', text: chatInput };
    setChatHistory(prev => [...prev, userMsg]);
    setChatInput('');
    setIsLoading(true);

    try {
      const response = await chatWithDocuments(pdfBase64List, chatHistory, chatInput);
      setChatHistory(prev => [...prev, { role: 'bot', text: response }]);
    } catch (err) {
      setChatHistory(prev => [...prev, { role: 'bot', text: "I encountered an error while analyzing your request." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const cardClass = isDarkMode ? 'bg-slate-900/40 border-slate-800' : 'bg-white border-slate-200 shadow-xl';

  return (
    <section className={`rounded-[3rem] overflow-hidden border ${cardClass} flex flex-col lg:flex-row min-h-[700px]`}>
      {/* Sidebar Info */}
      <div className={`p-10 lg:w-1/3 flex flex-col justify-between border-b lg:border-b-0 lg:border-r ${
        isDarkMode ? 'bg-black/30 border-slate-800' : 'bg-indigo-50/40 border-slate-200'
      }`}>
        <div className="space-y-10">
          <div>
            <div className="flex items-center gap-4 mb-6">
              <div className="p-3 rounded-2xl bg-violet-500/20 text-violet-400 shadow-inner">
                <MessageSquare className="w-7 h-7" />
              </div>
              <h3 className="text-2xl font-extrabold tracking-tight">Deep Dive Analyst</h3>
            </div>
            <p className={`text-base leading-relaxed font-medium ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
              Ask specific questions about the {pdfFiles.length} documents uploaded. I can compare figures across reports, explain strategic pivots, or verify specific financial claims.
            </p>
          </div>

          <div className="space-y-5">
            <h4 className="text-xs font-black text-slate-500 uppercase tracking-[0.25em]">Context Source</h4>
            <div className="space-y-3">
              {pdfFiles.map((file, i) => (
                <div key={i} className={`flex items-center gap-4 p-4 rounded-2xl border ${isDarkMode ? 'bg-slate-800/40 border-slate-700/50' : 'bg-white border-slate-200'}`}>
                  <Files className="w-5 h-5 text-indigo-400" />
                  <span className="text-sm font-bold truncate opacity-90">{file.name}</span>
                </div>
              ))}
            </div>
          </div>

          <div className="space-y-4">
             <h4 className="text-xs font-black text-slate-500 uppercase tracking-[0.25em]">Sample Queries</h4>
             {["Detail the ESG roadmap.", "Compare Q4 vs Q3 margins.", "What are the major risk factors?"].map((q, i) => (
               <button 
                key={i}
                onClick={() => setChatInput(q)}
                className={`w-full text-left text-sm p-5 rounded-2xl transition-all border-2 ${
                  isDarkMode ? 'bg-slate-900 border-slate-800 hover:border-indigo-500 hover:bg-slate-800/60' : 'bg-white border-slate-200 hover:border-indigo-400'
                } font-bold`}
               >
                 {q}
               </button>
             ))}
          </div>
        </div>
      </div>

      {/* Chat Area */}
      <div className="flex-1 flex flex-col p-8 relative bg-transparent">
        <div className="flex-1 overflow-y-auto space-y-8 mb-8 pr-4 custom-scrollbar">
          {chatHistory.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center opacity-40 text-center">
              <div className="w-28 h-28 rounded-full bg-indigo-500/10 flex items-center justify-center mb-8 animate-pulse">
                <Bot className="w-14 h-14 text-indigo-400" />
              </div>
              <p className="text-2xl font-black mb-2">Waiting for your query...</p>
              <p className="text-base font-medium">Type a question below to start exploring the documents.</p>
            </div>
          )}

          {chatHistory.map((msg, i) => (
            <div key={i} className={`flex gap-5 ${msg.role === 'user' ? 'flex-row-reverse' : ''} animate-in fade-in slide-in-from-bottom-4 duration-500`}>
              <div className={`w-12 h-12 rounded-[1.25rem] flex items-center justify-center flex-shrink-0 shadow-xl ${
                msg.role === 'user' ? 'bg-emerald-600' : 'bg-indigo-600'
              }`}>
                {msg.role === 'user' ? <User className="w-6 h-6 text-white" /> : <Bot className="w-6 h-6 text-white" />}
              </div>
              <div className={`p-6 rounded-[2rem] max-w-[85%] text-[1.05rem] leading-[1.7] shadow-lg font-medium ${
                msg.role === 'user'
                  ? `${isDarkMode ? 'bg-emerald-500/20 text-emerald-50 border border-emerald-500/30' : 'bg-emerald-50 text-emerald-950 border border-emerald-100'} rounded-tr-none`
                  : `${isDarkMode ? 'bg-slate-800 text-slate-100 border border-slate-700' : 'bg-slate-50 text-slate-900 border border-slate-200'} rounded-tl-none`
              }`}>
                {msg.text}
              </div>
            </div>
          ))}

          {isLoading && (
            <div className="flex gap-5">
              <div className="w-12 h-12 rounded-[1.25rem] flex items-center justify-center flex-shrink-0 bg-indigo-600 shadow-xl">
                <Loader2 className="w-6 h-6 animate-spin text-white" />
              </div>
              <div className={`p-6 rounded-[2rem] rounded-tl-none ${isDarkMode ? 'bg-slate-800/60' : 'bg-slate-100'} flex items-center gap-3`}>
                <span className="w-2 h-2 rounded-full bg-indigo-400 animate-bounce"></span>
                <span className="w-2 h-2 rounded-full bg-indigo-400 animate-bounce [animation-delay:0.2s]"></span>
                <span className="w-2 h-2 rounded-full bg-indigo-400 animate-bounce [animation-delay:0.4s]"></span>
              </div>
            </div>
          )}
          <div ref={chatEndRef} />
        </div>

        <form onSubmit={handleSubmit} className="relative mt-auto">
          <input
            type="text"
            value={chatInput}
            onChange={(e) => setChatInput(e.target.value)}
            placeholder="Search for details, trends, or specific figures..."
            className={`w-full pl-8 pr-16 py-6 rounded-[2rem] border-2 outline-none transition-all shadow-2xl text-lg font-semibold ${
              isDarkMode 
                ? 'bg-black/50 border-slate-700 focus:border-indigo-500 text-white placeholder:text-slate-600' 
                : 'bg-white border-slate-300 focus:border-indigo-500 text-slate-950 placeholder:text-slate-400'
            }`}
          />
          <button 
            type="submit"
            disabled={!chatInput.trim() || isLoading}
            className={`absolute right-4 top-4 p-4 rounded-2xl transition-all ${
              chatInput.trim() 
                ? 'bg-indigo-600 text-white shadow-xl hover:scale-105 active:scale-95' 
                : 'text-slate-600 pointer-events-none'
            }`}
          >
            <Send className="w-6 h-6" />
          </button>
        </form>
      </div>
    </section>
  );
};

export default ChatInterface;

