                {msg.role === 'user' ? <User className="w-4 h-4 text-white" /> : <Bot className="w-4 h-4 text-white" />}
              </div>
              <div className={`p-4 rounded-2xl max-w-[85%] text-[0.9rem] leading-relaxed shadow-sm font-medium ${
                msg.role === 'user'
                  ? `${isDarkMode ? 'bg-emerald-500/15 text-emerald-50 border border-emerald-500/20' : 'bg-emerald-50 text-emerald-950 border border-emerald-100'} rounded-tr-none`
                  : `${isDarkMode ? 'bg-slate-800 text-slate-100 border border-slate-700' : 'bg-slate-50 text-slate-900 border border-slate-200'} rounded-tl-none`
              }`}>
                {msg.text}
              </div>
            </div>
          ))}

          {isLoading && (
            <div className="flex gap-3">
              <div className="w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0 bg-indigo-600">
                <Loader2 className="w-4 h-4 animate-spin text-white" />
              </div>
              <div className={`p-4 rounded-2xl rounded-tl-none ${isDarkMode ? 'bg-slate-800/60' : 'bg-slate-100'} flex items-center gap-2`}>
                <span className="w-1 h-1 rounded-full bg-indigo-400 animate-bounce"></span>
                <span className="w-1 h-1 rounded-full bg-indigo-400 animate-bounce [animation-delay:0.2s]"></span>
                <span className="w-1 h-1 rounded-full bg-indigo-400 animate-bounce [animation-delay:0.4s]"></span>
              </div>
            </div>
          )}
          <div ref={chatEndRef} />
        </div>

        <form onSubmit={handleSubmit} className="relative mt-auto">
          <input
            type="text"
            value={chatInput}
            onChange={(e) => setChatInput(e.target.value)}
            placeholder="Search for details..."
            className={`w-full pl-5 pr-12 py-4 rounded-xl border outline-none transition-all shadow-lg text-sm font-semibold ${
              isDarkMode 
                ? 'bg-black/40 border-slate-700 focus:border-indigo-500 text-white placeholder:text-slate-600' 
                : 'bg-white border-slate-300 focus:border-indigo-500 text-slate-950 placeholder:text-slate-400'
            }`}
          />
          <button 
            type="submit"
            disabled={!chatInput.trim() || isLoading}
            className={`absolute right-2 top-2 p-2.5 rounded-lg transition-all ${
              chatInput.trim() 
                ? 'bg-indigo-600 text-white shadow-md hover:scale-105 active:scale-95' 
                : 'text-slate-600 pointer-events-none'
            }`}
          >
            <Send className="w-4 h-4" />
          </button>
        </form>
      </div>
    </section>
  );
};

export default ChatInterface;
